def create_db(table_name):
    c.execute('PRAGMA journal_mode = WAL')
    c.execute('CREATE TABLE IF NOT EXISTS ' + table_name + '(tweet_id INTEGER NOT NULL PRIMARY KEY, date_mined TEXT, screen_name TEXT,                                                             user_id INTEGER, users_name TEXT, created_at_UTC TEXT, is_retweet TEXT,                                                             retweeted_times TEXT, text TEXT, place_name TEXT, country_code TEXT, country TEXT,                                                             bounding_box TEXT, source_tweeted TEXT, geo TEXT, in_reply_to_user TEXT,                                                             inreply_statusid TEXT, posted_image_dest TEXT, tweeted_image BLOB, image_hash TEXT,                                                             media_type TEXT, media_url TEXT, media_id TEXT, posted_video_dest TEXT,                                                             tweeted_video BLOB, video_hash TEXT, video_type TEXT, video_url TEXT,                                                             url_in_tweet TEXT, status BLOB, status_hash TEXT, bookmark TEXT)')
    conn.commit()